impl Solution { pub fn min_moves_to_capture_the_queen(a: i32, b: i32, c: i32, d: i32, e: i32, f: i32) -> i32 { let (black_r, black_b) = (1, 1); if a == e && !(a == c && (b - d) * (d - f) > 0) || b == f && !(b == d && (a - c) * (c - e) > 0) { return 1; } if (c - d == e - f && !(c - d == a - b && (c - a) * (a - e) > 0)) || (c + d == e + f && !(c + d == a + b && (c - a) * (a - e) > 0)) { return 1; } 2 } }